// // This is a 1-bit wide 2-to-1 multiplexer with an active-low enable signal.
module mux2to1_1bit_active_high (
  input in0,
  input in1,
  input sel,
  input en,
  output reg out
);

  always @(*) begin
    if (en) begin
      case (sel)
        1'b0: out = in0;
        1'b1: out = in1;
        default: out = 1'b0;
      endcase
    end else begin
      out = 1'b0;
    end
  end

endmodule
